  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { useDispatch, useSelector } from 'react-redux';
  4	import { Button, Tooltip } from '@patternfly/react-core';
  5	import { consoleFetchJSON } from '@openshift-console/dynamic-plugin-sdk';
  6	
  7	import { getApiUrl } from '../config';
  8	import { getRequestInitWithAuthHeader } from '../hooks/useAuth';
  9	import { useBoolean } from '../hooks/useBoolean';
 10	import { useHideLightspeed } from '../hooks/useHideLightspeed';
 11	import { closeOLS, openOLS, userFeedbackDisable } from '../redux-actions';
 12	import { State } from '../redux-reducers';
 13	import ErrorBoundary from './ErrorBoundary';
 14	import GeneralPage from './GeneralPage';
 15	
 16	import './popover.css';
 17	
 18	// TODO: Include this for now to work around bug where CSS is not pulled in by console plugin SDK
 19	import './pf-styles.css';
 20	
 21	const FEEDBACK_STATUS_ENDPOINT = getApiUrl('/v1/feedback/status');
 22	const REQUEST_TIMEOUT = 5 * 60 * 1000;
 23	
 24	const Popover: React.FC = () => {
 25	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
 26	
 27	  const dispatch = useDispatch();
 28	
 29	  const isOpen = useSelector((s: State) => s.plugins?.ols?.get('isOpen'));
 30	
 31	  const [isExpanded, , expand, collapse] = useBoolean(false);
 32	  const [isHidden] = useHideLightspeed();
 33	
 34	  React.useEffect(() => {
 35	    consoleFetchJSON(
 36	      FEEDBACK_STATUS_ENDPOINT,
 37	      'get',
 38	      getRequestInitWithAuthHeader(),
 39	      REQUEST_TIMEOUT,
 40	    )
 41	      .then((response) => {
 42	        if (response.status?.enabled === false) {
 43	          dispatch(userFeedbackDisable());
 44	        }
 45	      })
 46	      .catch((error) => {
 47	        // eslint-disable-next-line no-console
 48	        console.error('Error fetching user feedback status:', error);
 49	      });
 50	  }, [dispatch]);
 51	
 52	  const open = React.useCallback(() => {
 53	    dispatch(openOLS());
 54	  }, [dispatch]);
 55	
 56	  const close = React.useCallback(() => {
 57	    dispatch(closeOLS());
 58	  }, [dispatch]);
 59	
 60	  if (isHidden) {
 61	    return null;
 62	  }
 63	
 64	  const title = t('Red Hat OpenShift Lightspeed');
 65	
 66	  return (
 67	    <div aria-label={title} className="ols-plugin__popover-container">
 68	      {isOpen ? (
 69	        <>
 70	          <div
 71	            className={`ols-plugin__popover ols-plugin__popover--${
 72	              isExpanded ? 'expanded' : 'collapsed'
 73	            }`}
 74	          >
 75	            {isExpanded ? (
 76	              <GeneralPage onClose={close} onCollapse={collapse} />
 77	            ) : (
 78	              <GeneralPage onClose={close} onExpand={expand} />
 79	            )}
 80	          </div>
 81	          <Button
 82	            aria-label={title}
 83	            className="ols-plugin__popover-button"
 84	            onClick={close}
 85	            variant="link"
 86	          />
 87	        </>
 88	      ) : (
 89	        <Tooltip content={title}>
 90	          <Button
 91	            aria-label={title}
 92	            className="ols-plugin__popover-button"
 93	            onClick={open}
 94	            variant="link"
 95	          />
 96	        </Tooltip>
 97	      )}
 98	    </div>
 99	  );
100	};
101	
102	const PopoverWithErrorBoundary: React.FC = () => (
103	  <ErrorBoundary>
104	    <Popover />
105	  </ErrorBoundary>
106	);
107	
108	export default PopoverWithErrorBoundary;

